const e=JSON.parse(`[{"id":1,"section":"A","theme":"Daily activities","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne court dans le parc","image_prompt":"A person running in a green park, sunny day"},{"id":"B","text":"Une personne fait du vélo","image_prompt":"A person riding a bicycle on a city path"},{"id":"C","text":"Une personne nage","image_prompt":"A person swimming in a blue pool"},{"id":"D","text":"Une personne marche avec un chien","image_prompt":"A person walking a golden retriever in a park"}],"correct":0,"transcript_fr":"J'adore commencer ma journée par un petit footing au parc quand il fait beau.","transcript_en":"I love starting my day with a quick jog in the park when the weather is nice.","points":[{"point":1,"male_lines":["J'adore commencer ma journée par un petit footing au parc quand il fait beau."],"female_lines":[]}]},{"id":2,"section":"A","theme":"Food and drink","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Quelqu'un boit un café","image_prompt":"A person holding a steaming cup of coffee"},{"id":"B","text":"Quelqu'un mange une pomme","image_prompt":"A person biting into a red apple"},{"id":"C","text":"Quelqu'un prépare un sandwich","image_prompt":"Hands making a sandwich with fresh ingredients"},{"id":"D","text":"Quelqu'un boit de l'eau","image_prompt":"A person drinking from a water bottle"}],"correct":1,"transcript_fr":"Pour le goûter, je préfère toujours prendre une pomme fraîche de mon arbre.","transcript_en":"For my afternoon snack, I always prefer to eat a fresh apple from my tree.","points":[{"point":1,"male_lines":["Pour le goûter, je préfère toujours prendre une pomme fraîche de mon arbre."],"female_lines":[]}]},{"id":3,"section":"A","theme":"Transportation","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Un autobus dans la rue","image_prompt":"A city bus on a busy street"},{"id":"B","text":"Une voiture dans un stationnement","image_prompt":"A car parked in a parking lot"},{"id":"C","text":"Un train à la gare","image_prompt":"A train arriving at a station platform"},{"id":"D","text":"Un avion à l'aéroport","image_prompt":"An airplane at an airport gate"}],"correct":2,"transcript_fr":"Le train de Montréal arrive toujours à l'heure à la gare centrale.","transcript_en":"The Montreal train always arrives on time at the central station.","points":[{"point":1,"male_lines":["Le train de Montréal arrive toujours à l'heure à la gare centrale."],"female_lines":[]}]},{"id":4,"section":"A","theme":"Weather","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Il neige dehors","image_prompt":"Snow falling on a winter street scene"},{"id":"B","text":"Il pleut avec un parapluie","image_prompt":"A person holding an umbrella in the rain"},{"id":"C","text":"Un soleil brillant","image_prompt":"Bright sun shining in a clear blue sky"},{"id":"D","text":"Un ciel nuageux","image_prompt":"Cloudy gray sky over a city"}],"correct":3,"transcript_fr":"N'oublie pas ton parapluie, il pleut des cordes aujourd'hui à Québec.","transcript_en":"Don't forget your umbrella, it's pouring rain today in Quebec City.","points":[{"point":1,"male_lines":["N'oublie pas ton parapluie, il pleut des cordes aujourd'hui à Québec."],"female_lines":[]}]},{"id":5,"section":"A","theme":"Shopping","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Une personne au supermarché","image_prompt":"A person pushing a shopping cart in a grocery store"},{"id":"B","text":"Une personne à la pharmacie","image_prompt":"A person at a pharmacy counter"},{"id":"C","text":"Une personne à la banque","image_prompt":"A person talking to a bank teller"},{"id":"D","text":"Une personne à la bibliothèque","image_prompt":"A person browsing books in a library"}],"correct":0,"transcript_fr":"Je dois aller à l'épicerie acheter du lait et du pain pour ce soir.","transcript_en":"I need to go to the grocery store to buy milk and bread for tonight.","points":[{"point":1,"male_lines":["Je dois aller à l'épicerie acheter du lait et du pain pour ce soir."],"female_lines":[]}]},{"id":6,"section":"A","theme":"Work","question":"Quelle image correspond le mieux à l'enregistrement ?","options":[{"id":"A","text":"Quelqu'un travaille sur un ordinateur","image_prompt":"A person typing on a laptop at a desk"},{"id":"B","text":"Quelqu'un parle au téléphone","image_prompt":"A person talking on a phone in an office"},{"id":"C","text":"Quelqu'un écrit à la main","image_prompt":"A person writing with a pen on paper"},{"id":"D","text":"Quelqu'un dans une réunion","image_prompt":"People sitting around a conference table"}],"correct":1,"transcript_fr":"Mon patron m'a demandé de l'appeler dès que je reçois ce courriel important.","transcript_en":"My boss asked me to call him as soon as I receive this important email.","points":[{"point":1,"male_lines":["Mon patron m'a demandé de l'appeler dès que je reçois ce courriel important."],"female_lines":[]}]},{"id":7,"section":"B","theme":"Making plans","question":"Quelle est la proposition de l'homme ?","options":[{"id":"A","text":"Aller au cinéma","image_prompt":""},{"id":"B","text":"Dîner au restaurant","image_prompt":""},{"id":"C","text":"Faire une promenade","image_prompt":""},{"id":"D","text":"Rester à la maison","image_prompt":""}],"correct":0,"transcript_fr":"Homme: Ça te dit d'aller voir ce nouveau film ce soir ? Femme: Bonne idée, à quelle heure ? Homme: Vers 19h, ça te va ? Femme: Parfait, je te retrouve devant le cinéma.","transcript_en":"Man: Would you like to go see this new movie tonight? Woman: Good idea, what time? Man: Around 7 PM, does that work for you? Woman: Perfect, I'll meet you in front of the cinema.","points":[{"point":1,"male_lines":["Ça te dit d'aller voir ce nouveau film ce soir ?","Vers 19h, ça te va ?"],"female_lines":["Bonne idée, à quelle heure ?","Parfait, je te retrouve devant le cinéma."]},{"point":2,"male_lines":["J'ai entendu dire que ce film était excellent.","On pourra prendre un verre après si tu veux."],"female_lines":["Oui, j'ai vu les critiques aussi.","Ça me va, il y a un bon café près du cinéma."]},{"point":3,"male_lines":["Je vais réserver les billets en ligne.","Tu préfères quelle place ?"],"female_lines":["Au milieu, ce serait parfait.","Merci de t'en occuper."]},{"point":4,"male_lines":["C'est fait, j'ai les billets.","À ce soir alors !"],"female_lines":["Super, j'ai hâte !","À tout à l'heure !"]}]},{"id":8,"section":"B","theme":"Asking for help","question":"Que demande la femme ?","options":[{"id":"A","text":"De l'argent","image_prompt":""},{"id":"B","text":"Des directions","image_prompt":""},{"id":"C","text":"L'heure","image_prompt":""},{"id":"D","text":"Un stylo","image_prompt":""}],"correct":1,"transcript_fr":"Femme: Excusez-moi, pourriez-vous m'indiquer où se trouve la station de métro la plus proche ? Homme: Bien sûr, continuez tout droit et tournez à gauche après la banque. Femme: Merci beaucoup, c'est à quelle distance ? Homme: Environ cinq minutes à pied.","transcript_en":"Woman: Excuse me, could you tell me where the nearest subway station is? Man: Of course, continue straight ahead and turn left after the bank. Woman: Thank you very much, how far is it? Man: About five minutes on foot.","points":[{"point":1,"male_lines":["Bien sûr, continuez tout droit et tournez à gauche après la banque.","Environ cinq minutes à pied."],"female_lines":["Excusez-moi, pourriez-vous m'indiquer où se trouve la station de métro la plus proche ?","Merci beaucoup, c'est à quelle distance ?"]},{"point":2,"male_lines":["C'est la station Berri-UQAM.","Vous ne pouvez pas la manquer."],"female_lines":["Ah oui, je la connais.","C'est parfait, merci encore."]},{"point":3,"male_lines":["Il y a aussi un arrêt d'autobus juste ici.","Mais le métro est plus rapide."],"female_lines":["Je préfère le métro en fait.","Je suis pressée."]},{"point":4,"male_lines":["Dans ce cas, suivez mes indications.","Bonne journée !"],"female_lines":["Merci beaucoup pour votre aide.","Bonne journée à vous aussi !"]}]},{"id":9,"section":"B","theme":"Shopping conversation","question":"Qu'est-ce que le client veut acheter ?","options":[{"id":"A","text":"Une chemise bleue","image_prompt":""},{"id":"B","text":"Un pantalon noir","image_prompt":""},{"id":"C","text":"Une veste en cuir","image_prompt":""},{"id":"D","text":"Des chaussures marron","image_prompt":""}],"correct":2,"transcript_fr":"Client: Bonjour, je cherche une veste en cuir comme celle en vitrine. Vendeuse: Oui, nous avons ce modèle en noir et en marron. Quelle taille faites-vous ? Client: Je fais du medium généralement. Vendeuse: Je vais chercher ça pour vous.","transcript_en":"Customer: Hello, I'm looking for a leather jacket like the one in the window. Saleswoman: Yes, we have this model in black and brown. What size do you wear? Customer: I'm usually a medium. Saleswoman: I'll go get that for you.","points":[{"point":1,"male_lines":["Bonjour, je cherche une veste en cuir comme celle en vitrine.","Je fais du medium généralement."],"female_lines":["Oui, nous avons ce modèle en noir et en marron. Quelle taille faites-vous ?","Je vais chercher ça pour vous."]},{"point":2,"male_lines":["La noire me plaît beaucoup.","Puis-je l'essayer ?"],"female_lines":["Bien sûr, les cabines sont par là.","Je vous attends ici."]},{"point":3,"male_lines":["Elle me va parfaitement.","Combien coûte-t-elle ?"],"female_lines":["Elle est en solde aujourd'hui.","Deux cent cinquante dollars."]},{"point":4,"male_lines":["C'est dans mon budget.","Je la prends."],"female_lines":["Excellent choix !","Voulez-vous un sac ?"]}]},{"id":10,"section":"B","theme":"Phone call","question":"Pourquoi la femme téléphone-t-elle ?","options":[{"id":"A","text":"Pour prendre rendez-vous chez le dentiste","image_prompt":""},{"id":"B","text":"Pour annuler une réservation","image_prompt":""},{"id":"C","text":"Pour commander une pizza","image_prompt":""},{"id":"D","text":"Pour réserver un taxi","image_prompt":""}],"correct":0,"transcript_fr":"Femme: Bonjour, je voudrais prendre rendez-vous avec le Dr. Tremblay s'il vous plaît. Réceptionniste: Bien sûr, pour quelle raison ? Femme: C'est pour un contrôle annuel. Réceptionniste: Le Dr. Tremblay est disponible mardi prochain à 14h.","transcript_en":"Woman: Hello, I would like to make an appointment with Dr. Tremblay please. Receptionist: Of course, for what reason? Woman: It's for an annual check-up. Receptionist: Dr. Tremblay is available next Tuesday at 2 PM.","points":[{"point":1,"male_lines":["Bien sûr, pour quelle raison ?","Le Dr. Tremblay est disponible mardi prochain à 14h."],"female_lines":["Bonjour, je voudrais prendre rendez-vous avec le Dr. Tremblay s'il vous plaît.","C'est pour un contrôle annuel."]},{"point":2,"male_lines":["Cela vous convient-il ?","Parfait, je note votre nom."],"female_lines":["Oui, mardi à 14h me va très bien.","C'est Marie Lefebvre."]},{"point":3,"male_lines":["Merci madame Lefebvre.","N'oubliez pas votre carte d'assurance maladie."],"female_lines":["Je l'aurai avec moi.","À mardi alors."]},{"point":4,"male_lines":["À mardi, bonne journée !","Au revoir."],"female_lines":["Merci, au revoir !","Bonne journée."]}]},{"id":11,"section":"C","theme":"Airport announcement","question":"Quel est le sujet principal de cette annonce ?","options":[{"id":"A","text":"Un retard de vol","image_prompt":""},{"id":"B","text":"L'embarquement immédiat","image_prompt":""},{"id":"C","text":"Un changement de porte","image_prompt":""},{"id":"D","text":"La perte de bagages","image_prompt":""}],"correct":1,"transcript_fr":"Mesdames et messieurs, le vol Air Canada trois-quatre-sept à destination de Toronto est maintenant prêt pour l'embarquement. Les passagers voyageant en classe affaires et les passagers avec des enfants en bas âge sont priés de se présenter à la porte douze. Nous vous remercions de bien vouloir avoir votre carte d'embarquement et votre pièce d'identité à portée de main. L'embarquement pour les autres passagers débutera dans dix minutes. Merci de votre attention.","transcript_en":"Ladies and gentlemen, Air Canada flight three-four-seven to Toronto is now ready for boarding. Passengers traveling in business class and passengers with infants are requested to proceed to gate twelve. We thank you for having your boarding pass and identification ready. Boarding for other passengers will begin in ten minutes. Thank you for your attention.","points":[{"point":1,"male_lines":["Mesdames et messieurs, le vol Air Canada trois-quatre-sept à destination de Toronto est maintenant prêt pour l'embarquement.","Les passagers voyageant en classe affaires et les passagers avec des enfants en bas âge sont priés de se présenter à la porte douze."],"female_lines":[]},{"point":2,"male_lines":["Nous vous remercions de bien vouloir avoir votre carte d'embarquement et votre pièce d'identité à portée de main.","L'embarquement pour les autres passagers débutera dans dix minutes."],"female_lines":[]},{"point":3,"male_lines":["Merci de votre attention.",""],"female_lines":[]}]},{"id":12,"section":"C","theme":"Supermarket announcement","question":"Que demande l'annonce ?","options":[{"id":"A","text":"De quitter le magasin","image_prompt":""},{"id":"B","text":"De se rendre au service client","image_prompt":""},{"id":"C","text":"De signaler une voiture mal garée","image_prompt":""},{"id":"D","text":"De profiter des soldes","image_prompt":""}],"correct":2,"transcript_fr":"Attention s'il vous plaît, le propriétaire de la voiture immatriculée trois-vingt-sept-vingt-six-quatre, vous êtes prié de vous rendre immédiatement sur le parking. Votre véhicule bloque la sortie d'urgence. Merci de bien vouloir déplacer votre automobile dans les plus brefs délais. Nous vous prions de nous excuser pour la gêne occasionnée.","transcript_en":"Attention please, the owner of the vehicle with license plate thirty-seven-twenty-six-four, you are requested to proceed immediately to the parking lot. Your vehicle is blocking the emergency exit. Please move your car as soon as possible. We apologize for any inconvenience caused.","points":[{"point":1,"male_lines":["Attention s'il vous plaît, le propriétaire de la voiture immatriculée trois-vingt-sept-vingt-six-quatre, vous êtes prié de vous rendre immédiatement sur le parking.","Votre véhicule bloque la sortie d'urgence."],"female_lines":[]},{"point":2,"male_lines":["Merci de bien vouloir déplacer votre automobile dans les plus brefs délais.","Nous vous prions de nous excuser pour la gêne occasionnée."],"female_lines":[]}]},{"id":13,"section":"C","theme":"Museum announcement","question":"Quelle information est donnée ?","options":[{"id":"A","text":"Le musée ferme dans une heure","image_prompt":""},{"id":"B","text":"Une nouvelle exposition est ouverte","image_prompt":""},{"id":"C","text":"Les visites guidées sont gratuites","image_prompt":""},{"id":"D","text":"Le café est fermé pour rénovation","image_prompt":""}],"correct":0,"transcript_fr":"Chers visiteurs, nous vous informons que le Musée des Beaux-Arts fermera ses portes dans exactement une heure, soit à dix-sept heures. Nous vous invitons à terminer votre visite et à vous diriger vers les sorties. N'oubliez pas de passer par la boutique de souvenirs qui reste ouverte jusqu'à dix-huit heures. Merci de votre compréhension et à bientôt.","transcript_en":"Dear visitors, we inform you that the Museum of Fine Arts will close its doors in exactly one hour, at five PM. We invite you to finish your visit and proceed to the exits. Don't forget to stop by the souvenir shop which remains open until six PM. Thank you for your understanding and see you soon.","points":[{"point":1,"male_lines":["Chers visiteurs, nous vous informons que le Musée des Beaux-Arts fermera ses portes dans exactement une heure, soit à dix-sept heures.","Nous vous invitons à terminer votre visite et à vous diriger vers les sorties."],"female_lines":[]},{"point":2,"male_lines":["N'oubliez pas de passer par la boutique de souvenirs qui reste ouverte jusqu'à dix-huit heures.","Merci de votre compréhension et à bientôt."],"female_lines":[]}]},{"id":14,"section":"C","theme":"Train station announcement","question":"Quel changement est annoncé ?","options":[{"id":"A","text":"Le train est annulé","image_prompt":""},{"id":"B","text":"Le train partira du quai trois","image_prompt":""},{"id":"C","text":"Le train a quinze minutes de retard","image_prompt":""},{"id":"D","text":"Le train est complet","image_prompt":""}],"correct":2,"transcript_fr":"Voyageurs du train VIA Rail numéro soixante-trois à destination d'Ottawa, nous vous informons que votre départ est retardé de quinze minutes en raison de travaux sur la voie. Le train partira maintenant à quatorze heures trente au lieu de quatorze heures quinze. Nous vous prions de bien vouloir patienter dans la salle d'attente. Veuillez accepter nos excuses pour ce contretemps.","transcript_en":"Passengers of VIA Rail train number sixty-three to Ottawa, we inform you that your departure is delayed by fifteen minutes due to track work. The train will now depart at two-thirty PM instead of two-fifteen PM. We ask you to please wait in the waiting room. Please accept our apologies for this delay.","points":[{"point":1,"male_lines":["Voyageurs du train VIA Rail numéro soixante-trois à destination d'Ottawa, nous vous informons que votre départ est retardé de quinze minutes en raison de travaux sur la voie.","Le train partira maintenant à quatorze heures trente au lieu de quatorze heures quinze."],"female_lines":[]},{"point":2,"male_lines":["Nous vous prions de bien vouloir patienter dans la salle d'attente.","Veuillez accepter nos excuses pour ce contretemps."],"female_lines":[]}]},{"id":15,"section":"C","theme":"Hospital announcement","question":"Que se passe-t-il ?","options":[{"id":"A","text":"Une visite médicale est obligatoire","image_prompt":""},{"id":"B","text":"Le docteur Martin est appelé en urgence","image_prompt":""},{"id":"C","text":"Les visites sont interdites","image_prompt":""},{"id":"D","text":"Le parking est complet","image_prompt":""}],"correct":1,"transcript_fr":"Le docteur Martin, vous êtes demandé immédiatement aux urgences. Le docteur Martin, salle d'urgence numéro quatre. C'est un appel urgent. Merci. Le docteur Martin, s'il vous plaît, vous êtes requis aux urgences immédiatement.","transcript_en":"Dr. Martin, you are requested immediately in the emergency room. Dr. Martin, emergency room number four. This is an urgent call. Thank you. Dr. Martin, please, you are required in the emergency room immediately.","points":[{"point":1,"male_lines":["Le docteur Martin, vous êtes demandé immédiatement aux urgences.","Le docteur Martin, salle d'urgence numéro quatre."],"female_lines":[]},{"point":2,"male_lines":["C'est un appel urgent.","Merci."],"female_lines":[]},{"point":3,"male_lines":["Le docteur Martin, s'il vous plaît, vous êtes requis aux urgences immédiatement.",""],"female_lines":[]}]},{"id":16,"section":"C","theme":"University announcement","question":"Quelle information est communiquée ?","options":[{"id":"A","text":"Les examens sont reportés","image_prompt":""},{"id":"B","text":"La bibliothèque fermera tôt","image_prompt":""},{"id":"C","text":"Un cours est annulé","image_prompt":""},{"id":"D","text":"Les inscriptions sont ouvertes","image_prompt":""}],"correct":2,"transcript_fr":"Étudiants du cours de biologie moléculaire, veuillez noter que le cours de cet après-midi est annulé en raison de l'absence du professeur. Le cours sera reporté à la semaine prochaine. Consultez votre portail étudiant pour les nouvelles dates. Merci de votre compréhension.","transcript_en":"Students of molecular biology class, please note that this afternoon's class is canceled due to the professor's absence. The class will be postponed to next week. Check your student portal for new dates. Thank you for your understanding.","points":[{"point":1,"male_lines":["Étudiants du cours de biologie moléculaire, veuillez noter que le cours de cet après-midi est annulé en raison de l'absence du professeur.","Le cours sera reporté à la semaine prochaine."],"female_lines":[]},{"point":2,"male_lines":["Consultez votre portail étudiant pour les nouvelles dates.","Merci de votre compréhension."],"female_lines":[]}]},{"id":17,"section":"D","theme":"Restaurant complaint","question":"Quelle est l'intention du client ?","options":[{"id":"A","text":"Féliciter le chef","image_prompt":""},{"id":"B","text":"Se plaindre du service","image_prompt":""},{"id":"C","text":"Demander l'addition","image_prompt":""},{"id":"D","text":"Réserver une table","image_prompt":""}],"correct":1,"transcript_fr":"Client: Excusez-moi, j'attends mon plat depuis quarante-cinq minutes. Serveur: Je suis désolé monsieur, il y a beaucoup de monde ce soir. Client: Je comprends, mais ce n'est pas acceptable. Serveur: Je vais vérifier en cuisine immédiatement.","transcript_en":"Customer: Excuse me, I've been waiting for my dish for forty-five minutes. Waiter: I'm sorry sir, it's very busy tonight. Customer: I understand, but this is not acceptable. Waiter: I'll check with the kitchen immediately.","points":[{"point":1,"male_lines":["Excusez-moi, j'attends mon plat depuis quarante-cinq minutes.","Je comprends, mais ce n'est pas acceptable."],"female_lines":["Je suis désolé monsieur, il y a beaucoup de monde ce soir.","Je vais vérifier en cuisine immédiatement."]},{"point":2,"male_lines":["J'avais commandé un steak saignant.","Il arrive froid maintenant."],"female_lines":["Je vais faire remplacer votre plat.","Mes sincères excuses."]},{"point":3,"male_lines":["Je ne veux plus attendre.","C'est vraiment décevant."],"female_lines":["Je vais parler au directeur.","Un dessert vous sera offert."]},{"point":4,"male_lines":["J'espère que ce sera réglé vite.","Je ne reviendrai plus sinon."],"female_lines":["Soyez assuré que nous allons régler ça.","Votre satisfaction est notre priorité."]}]},{"id":18,"section":"D","theme":"Job interview","question":"Que veut savoir le recruteur ?","options":[{"id":"A","text":"Les compétences en informatique","image_prompt":""},{"id":"B","text":"La disponibilité immédiate","image_prompt":""},{"id":"C","text":"L'expérience professionnelle","image_prompt":""},{"id":"D","text":"Les attentes salariales","image_prompt":""}],"correct":2,"transcript_fr":"Recruteur: Pouvez-vous me parler de votre expérience précédente ? Candidat: J'ai travaillé cinq ans dans le marketing digital. Recruteur: Quelles étaient vos principales responsabilités ? Candidat: Je gérais les réseaux sociaux et les campagnes publicitaires.","transcript_en":"Recruiter: Can you tell me about your previous experience? Candidate: I worked five years in digital marketing. Recruiter: What were your main responsibilities? Candidate: I managed social media and advertising campaigns.","points":[{"point":1,"male_lines":["Pouvez-vous me parler de votre expérience précédente ?","Quelles étaient vos principales responsabilités ?"],"female_lines":["J'ai travaillé cinq ans dans le marketing digital.","Je gérais les réseaux sociaux et les campagnes publicitaires."]},{"point":2,"male_lines":["Avez-vous dirigé une équipe ?","Comment mesuriez-vous le succès ?"],"female_lines":["Oui, j'avais trois personnes sous ma responsabilité.","Via les taux de conversion et l'engagement."]},{"point":3,"male_lines":["Pourquoi voulez-vous changer d'entreprise ?","Qu'attendez-vous de ce poste ?"],"female_lines":["Je cherche de nouveaux défis.","Une entreprise avec une vision innovante."]},{"point":4,"male_lines":["Nous apprécions votre profil.","Nous vous contacterons sous peu."],"female_lines":["Merci pour cette entrevue.","J'attends votre retour avec impatience."]}]},{"id":19,"section":"D","theme":"Neighbor dispute","question":"Quel est le problème entre les voisins ?","options":[{"id":"A","text":"Le bruit tard le soir","image_prompt":""},{"id":"B","text":"Les chiens qui aboient","image_prompt":""},{"id":"C","text":"La cloture délimitant les terrains","image_prompt":""},{"id":"D","text":"Les feuilles qui tombent","image_prompt":""}],"correct":0,"transcript_fr":"Voisin: Votre musique est très forte à minuit, c'est difficile de dormir. Voisine: Je suis désolée, je ne pensais pas que cela vous dérangeait. Voisin: Ça fait trois soirs de suite. Voisine: Je vais baisser le volume à partir de ce soir.","transcript_en":"Neighbor: Your music is very loud at midnight, it's hard to sleep. Neighbor (female): I'm sorry, I didn't think it bothered you. Neighbor: It's been three nights in a row. Neighbor (female): I'll turn down the volume starting tonight.","points":[{"point":1,"male_lines":["Votre musique est très forte à minuit, c'est difficile de dormir.","Ça fait trois soirs de suite."],"female_lines":["Je suis désolée, je ne pensais pas que cela vous dérangeait.","Je vais baisser le volume à partir de ce soir."]},{"point":2,"male_lines":["J'ai des enfants qui se lèvent tôt.","Ils ne peuvent pas bien se reposer."],"female_lines":["Je comprends tout à fait.","Je vais mettre des écouteurs à l'avenir."]},{"point":3,"male_lines":["Ce serait apprécié.","Nous voulons rester de bons voisins."],"female_lines":["Absolument, moi aussi.","Excusez-moi encore pour le dérangement."]},{"point":4,"male_lines":["Pas de problème, merci de votre compréhension.","Bonne soirée."],"female_lines":["Bonne soirée à vous aussi.","À bientôt."]}]},{"id":20,"section":"D","theme":"Return policy","question":"Que veut faire la cliente ?","options":[{"id":"A","text":"Échanger un article défectueux","image_prompt":""},{"id":"B","text":"Obtenir un remboursement","image_prompt":""},{"id":"C","text":"Acheter un accessoire","image_prompt":""},{"id":"D","text":"Prendre un rendez-vous","image_prompt":""}],"correct":0,"transcript_fr":"Cliente: Bonjour, j'aimerais échanger ce lecteur DVD, il ne fonctionne pas. Employé: Avez-vous le ticket de caisse ? Cliente: Oui, je l'ai acheté hier. Employé: Pas de problème, je vais vous le remplacer.","transcript_en":"Customer: Hello, I would like to exchange this DVD player, it doesn't work. Employee: Do you have the receipt? Customer: Yes, I bought it yesterday. Employee: No problem, I'll replace it for you.","points":[{"point":1,"male_lines":["Avez-vous le ticket de caisse ?","Pas de problème, je vais vous le remplacer."],"female_lines":["Bonjour, j'aimerais échanger ce lecteur DVD, il ne fonctionne pas.","Oui, je l'ai acheté hier."]},{"point":2,"male_lines":["Voulez-vous le même modèle ?","Ou préférez-vous un remboursement ?"],"female_lines":["Le même modèle, s'il vous plaît.","J'espère que celui-là marchera."]},{"point":3,"male_lines":["Je vais tester celui-ci devant vous.","Vous avez trente jours pour retourner."],"female_lines":["C'est rassurant, merci.","C'est une bonne politique."]},{"point":4,"male_lines":["Voici votre nouveau lecteur.","Bonne journée madame."],"female_lines":["Merci beaucoup pour votre aide.","Bonne journée à vous."]}]},{"id":21,"section":"D","theme":"Doctor appointment","question":"Pourquoi le patient appelle-t-il ?","options":[{"id":"A","text":"Pour annuler son rendez-vous","image_prompt":""},{"id":"B","text":"Pour demander une ordonnance","image_prompt":""},{"id":"C","text":"Pour signaler une réaction allergique","image_prompt":""},{"id":"D","text":"Pour prendre un rendez-vous urgent","image_prompt":""}],"correct":3,"transcript_fr":"Patient: Bonjour, j'ai une douleur très forte à la jambe depuis ce matin. Secrétaire: C'est une urgence ? Patient: Oui, je ne peux presque plus marcher. Secrétaire: Venez à quatorze heures, le docteur vous recevra.","transcript_en":"Patient: Hello, I have very strong pain in my leg since this morning. Secretary: Is it an emergency? Patient: Yes, I can barely walk anymore. Secretary: Come at two PM, the doctor will see you.","points":[{"point":1,"male_lines":["Bonjour, j'ai une douleur très forte à la jambe depuis ce matin.","Oui, je ne peux presque plus marcher."],"female_lines":["C'est une urgence ?","Venez à quatorze heures, le docteur vous recevra."]},{"point":2,"male_lines":["Je peux venir plus tôt ?","J'ai vraiment mal."],"female_lines":["Le docteur est complet ce matin.","Mais quatorze heures est confirmé."]},{"point":3,"male_lines":["D'accord, j'arriverai à l'heure.","Dois-je apporter quelque chose ?"],"female_lines":["Votre carte d'assurance maladie.","Et la liste de vos médicaments."]},{"point":4,"male_lines":["C'est noté, merci.","À tout à l'heure."],"female_lines":["À quatorze heures précises.","Au revoir monsieur."]}]},{"id":22,"section":"D","theme":"Bank inquiry","question":"Que demande le client à la banque ?","options":[{"id":"A","text":"Un prêt immobilier","image_prompt":""},{"id":"B","text":"Une augmentation de découvert","image_prompt":""},{"id":"C","text":"L'ouverture d'un compte","image_prompt":""},{"id":"D","text":"Le blocage de sa carte","image_prompt":""}],"correct":1,"transcript_fr":"Client: J'aimerais augmenter mon découvert autorisé, s'il vous plaît. Conseiller: Quel montant souhaitez-vous ? Client: Passer de cinq cents à mille dollars. Conseiller: Je vais vérifier votre dossier.","transcript_en":"Client: I would like to increase my overdraft limit, please. Advisor: What amount would you like? Client: Go from five hundred to one thousand dollars. Advisor: I'll check your file.","points":[{"point":1,"male_lines":["J'aimerais augmenter mon découvert autorisé, s'il vous plaît.","Passer de cinq cents à mille dollars."],"female_lines":["Quel montant souhaitez-vous ?","Je vais vérifier votre dossier."]},{"point":2,"male_lines":["J'en ai besoin pour des travaux urgents.","Ma situation financière est stable."],"female_lines":["Votre historique est bon.","L'augmentation est approuvée."]},{"point":3,"male_lines":["Excellent, merci beaucoup.","Quand est-ce effectif ?"],"female_lines":["Immédiatement.","Vous recevrez une confirmation par courriel."]},{"point":4,"male_lines":["Parfait, je vous remercie.","Bonne journée."],"female_lines":["Je vous en prie.","Bonne journée monsieur."]}]},{"id":23,"section":"E","theme":"Radio interview - Environment","question":"Quel est le sujet principal de l'interview ?","options":[{"id":"A","text":"La pollution de l'air","image_prompt":""},{"id":"B","text":"Le recyclage des plastiques","image_prompt":""},{"id":"C","text":"La protection des forêts","image_prompt":""},{"id":"D","text":"L'énergie solaire","image_prompt":""}],"correct":2,"transcript_fr":"Journaliste: Bonjour madame Dubois, vous êtes experte en environnement. Invitée: Bonjour, merci de m'accueillir. Journaliste: Parlez-nous de l'importance des forêts boréales. Invitée: Elles absorbent trente pour cent du CO2 mondial.","transcript_en":"Journalist: Hello Ms. Dubois, you are an environment expert. Guest: Hello, thank you for having me. Journalist: Tell us about the importance of boreal forests. Guest: They absorb thirty percent of global CO2.","points":[{"point":1,"male_lines":["Bonjour madame Dubois, vous êtes experte en environnement.","Parlez-nous de l'importance des forêts boréales."],"female_lines":["Bonjour, merci de m'accueillir.","Elles absorbent trente pour cent du CO2 mondial."]},{"point":2,"male_lines":["Quels sont les principaux menaces ?","Comment peut-on les protéger ?"],"female_lines":["La déforestation et les feux de forêt.","Par des politiques de conservation strictes."]},{"point":3,"male_lines":["Le Canada joue un rôle important ?","Quelles sont vos recommandations ?"],"female_lines":["Absolument, nous avons la plus grande forêt boréale.","Il faut interdire la coupe à blanc."]},{"point":4,"male_lines":["Merci pour ces informations cruciales.","Un dernier mot ?"],"female_lines":["Agissons avant qu'il ne soit trop tard.","Chaque arbre compte."]}]},{"id":24,"section":"E","theme":"Radio interview - Technology","question":"Quelle innovation est discutée ?","options":[{"id":"A","text":"Les voitures autonomes","image_prompt":""},{"id":"B","text":"La réalité virtuelle","image_prompt":""},{"id":"C","text":"L'intelligence artificielle","image_prompt":""},{"id":"D","text":"Les drones de livraison","image_prompt":""}],"correct":0,"transcript_fr":"Journaliste: Monsieur Lavoie, votre entreprise développe des voitures autonomes. Invité: Oui, nous testons actuellement à Montréal. Journaliste: Quels sont les avantages ? Invité: Moins d'accidents et une mobilité pour tous.","transcript_en":"Journalist: Mr. Lavoie, your company is developing autonomous cars. Guest: Yes, we are currently testing in Montreal. Journalist: What are the advantages? Guest: Fewer accidents and mobility for everyone.","points":[{"point":1,"male_lines":["Monsieur Lavoie, votre entreprise développe des voitures autonomes.","Quels sont les avantages ?"],"female_lines":["Oui, nous testons actuellement à Montréal.","Moins d'accidents et une mobilité pour tous."]},{"point":2,"male_lines":["Qu'en est-il de la sécurité ?","Les gens ont-ils confiance ?"],"female_lines":["Nos tests montrent quatre-vingt-dix pour cent moins d'accidents.","La confiance se construit progressivement."]},{"point":3,"male_lines":["Quand seront-elles disponibles ?","Quel sera le coût ?"],"female_lines":["D'ici deux ans pour les taxis.","Le prix sera comparable aux voitures actuelles."]},{"point":4,"male_lines":["Merci pour ces précisions.","Dernier mot ?"],"female_lines":["L'avenir de la mobilité est autonome.","Et il arrive plus vite qu'on ne pense."]}]},{"id":25,"section":"E","theme":"Radio interview - Health","question":"Quel conseil santé est donné ?","options":[{"id":"A","text":"Dormir huit heures par nuit","image_prompt":""},{"id":"B","text":"Boire deux litres d'eau par jour","image_prompt":""},{"id":"C","text":"Marcher trente minutes par jour","image_prompt":""},{"id":"D","text":"Manger cinq fruits et légumes","image_prompt":""}],"correct":2,"transcript_fr":"Journaliste: Docteur Gagnon, quel exercice recommandez-vous ? Médecin: La marche rapide, trente minutes quotidiennes. Journaliste: Pourquoi la marche spécifiquement ? Médecin: C'est accessible à tous et très efficace pour le cœur.","transcript_en":"Journalist: Dr. Gagnon, what exercise do you recommend? Doctor: Brisk walking, thirty minutes daily. Journalist: Why walking specifically? Doctor: It's accessible to everyone and very effective for the heart.","points":[{"point":1,"male_lines":["Docteur Gagnon, quel exercice recommandez-vous ?","Pourquoi la marche spécifiquement ?"],"female_lines":["La marche rapide, trente minutes quotidiennes.","C'est accessible à tous et très efficace pour le cœur."]},{"point":2,"male_lines":["Faut-il marcher vite ?","À quelle heure de la journée ?"],"female_lines":["Un rythme soutenu est idéal.","Le matin ou le soir, selon vos préférences."]},{"point":3,"male_lines":["Quels sont les autres bienfaits ?","Pour les personnes âgées aussi ?"],"female_lines":["Cela réduit le stress et améliore le sommeil.","Particulièrement recommandé pour les seniors."]},{"point":4,"male_lines":["Merci docteur pour ces conseils.","Un message final ?"],"female_lines":["Bougez plus, restez actif.","Votre corps vous dira merci."]}]},{"id":26,"section":"E","theme":"Radio interview - Culture","question":"Quel événement culturel est présenté ?","options":[{"id":"A","text":"Un festival de jazz","image_prompt":""},{"id":"B","text":"Une exposition de peinture","image_prompt":""},{"id":"C","text":"Un marathon de cinéma","image_prompt":""},{"id":"D","text":"Une foire du livre","image_prompt":""}],"correct":0,"transcript_fr":"Journaliste: Madame Roy, le festival de jazz approche. Organisatrice: Oui, notre vingtième édition commence vendredi. Journaliste: Quels artistes seront présents ? Organisatrice: Nous avons des musiciens du monde entier.","transcript_en":"Journalist: Ms. Roy, the jazz festival is approaching. Organizer: Yes, our twentieth edition starts Friday. Journalist: Which artists will be present? Organizer: We have musicians from around the world.","points":[{"point":1,"male_lines":["Madame Roy, le festival de jazz approche.","Quels artistes seront présents ?"],"female_lines":["Oui, notre vingtième édition commence vendredi.","Nous avons des musiciens du monde entier."]},{"point":2,"male_lines":["Combien de concerts au total ?","Où se déroulent-ils ?"],"female_lines":["Plus de cinquante spectacles.","Dans plusieurs salles du centre-ville."]},{"point":3,"male_lines":["Les billets sont-ils encore disponibles ?","Quel est le prix ?"],"female_lines":["Oui, mais il reste peu de places.","Entre vingt et soixante dollars."]},{"point":4,"male_lines":["Merci pour ces informations.","Un mot pour conclure ?"],"female_lines":["Venez célébrer la musique avec nous.","Ce sera magique."]}]},{"id":27,"section":"F","theme":"Urban planning debate","question":"Quelle est l'opinion principale des intervenants ?","options":[{"id":"A","text":"Construire plus de routes","image_prompt":""},{"id":"B","text":"Développer les transports en commun","image_prompt":""},{"id":"C","text":"Interdire les voitures en centre-ville","image_prompt":""},{"id":"D","text":"Augmenter le prix du stationnement","image_prompt":""}],"correct":1,"transcript_fr":"Modérateur: Discutons des transports à Montréal. Participant A: Nous devons investir dans le métro et les bus. Modérateur: Participant B, votre avis ? Participant B: Je suis d'accord, mais il faut aussi des pistes cyclables.","transcript_en":"Moderator: Let's discuss transportation in Montreal. Participant A: We must invest in the metro and buses. Moderator: Participant B, your opinion? Participant B: I agree, but we also need bike lanes.","points":[{"point":1,"male_lines":["Discutons des transports à Montréal.","Participant B, votre avis ?"],"female_lines":["Nous devons investir dans le métro et les bus.","Je suis d'accord, mais il faut aussi des pistes cyclables."]},{"point":2,"male_lines":["Les voitures causent trop de pollution.","Qu'en pensez-vous du tramway ?"],"female_lines":["Absolument, c'est insoutenable.","Le tramway serait une excellente solution."]},{"point":3,"male_lines":["Mais cela coûte cher.","Comment financer ces projets ?"],"female_lines":["Via des taxes sur les véhicules polluants.","Et des partenariats publics-privés."]},{"point":4,"male_lines":["Des idées concrètes pour commencer ?","Un consensus semble possible ?"],"female_lines":["Commençons par une ligne de bus rapide.","Oui, l'urgence climatique nous unit."]}]},{"id":28,"section":"F","theme":"Education reform discussion","question":"Sur quoi porte le désaccord ?","options":[{"id":"A","text":"Le nombre d'heures de cours","image_prompt":""},{"id":"B","text":"L'introduction de la technologie","image_prompt":""},{"id":"C","text":"Les méthodes d'évaluation","image_prompt":""},{"id":"D","text":"Les langues enseignées","image_prompt":""}],"correct":2,"transcript_fr":"Enseignant A: Les examens standardisés ne reflètent pas les vraies compétences. Enseignant B: Mais ils permettent de comparer objectivement. Enseignant A: L'évaluation devrait être continue et personnalisée.","transcript_en":"Teacher A: Standardized exams don't reflect real skills. Teacher B: But they allow objective comparison. Teacher A: Assessment should be continuous and personalized.","points":[{"point":1,"male_lines":["Les examens standardisés ne reflètent pas les vraies compétences.","L'évaluation devrait être continue et personnalisée."],"female_lines":["Mais ils permettent de comparer objectivement.","Comment évaluer sans critères communs ?"]},{"point":2,"male_lines":["Via des projets concrets et des portfolios.","Cela développe l'autonomie."],"female_lines":["C'est plus difficile à standardiser.","Les universités ont besoin de notes."]},{"point":3,"male_lines":["Les portfolios montrent mieux les progrès.","Pas seulement un chiffre final."],"female_lines":["Cela demande plus de temps aux enseignants.","Sommes-nous prêts pour ce changement ?"]},{"point":4,"male_lines":["Il faut former les profs d'abord.","Un compromis est possible ?"],"female_lines":["Absolument, la formation est clé.","Mélangeons les deux approches."]}]},{"id":29,"section":"F","theme":"Work-life balance","question":"Quelle solution est privilégiée ?","options":[{"id":"A","text":"Le télétravail permanent","image_prompt":""},{"id":"B","text":"La semaine de quatre jours","image_prompt":""},{"id":"C","text":"Des horaires flexibles","image_prompt":""},{"id":"D","text":"Plus de congés payés","image_prompt":""}],"correct":2,"transcript_fr":"Employé A: Je préfère des horaires flexibles pour concilier famille et travail. Employé B: C'est pratique, mais il faut des heures de présence communes. Employé A: Oui, disons dix heures à quinze heures obligatoires.","transcript_en":"Employee A: I prefer flexible hours to balance family and work. Employee B: It's practical, but we need common presence hours. Employee A: Yes, let's say ten AM to three PM mandatory.","points":[{"point":1,"male_lines":["Je préfère des horaires flexibles pour concilier famille et travail.","Oui, disons dix heures à quinze heures obligatoires."],"female_lines":["C'est pratique, mais il faut des heures de présence communes.","Le reste du temps en libre choix ?"]},{"point":2,"male_lines":["Exactement, pour les réunions d'équipe.","Cela améliore la productivité."],"female_lines":["Je suis d'accord sur le principe.","Mais certains abusent du système."]},{"point":3,"male_lines":["Il faut des objectifs clairs.","Pas compter les heures."],"female_lines":["Mesurer les résultats, pas le temps.","C'est plus juste ainsi."]},{"point":4,"male_lines":["Proposons ce modèle à la direction.","Ils seront convaincus ?"],"female_lines":["Avec des données sur la productivité.","C'est notre meilleur argument."]}]},{"id":30,"section":"F","theme":"Housing crisis","question":"Quelle mesure est suggérée ?","options":[{"id":"A","text":"Construire des gratte-ciel","image_prompt":""},{"id":"B","text":"Réguler les loyers","image_prompt":""},{"id":"C","text":"Déménager les industries","image_prompt":""},{"id":"D","text":"Augmenter les taxes foncières","image_prompt":""}],"correct":1,"transcript_fr":"Citoyen A: Les loyers augmentent trop vite à Vancouver. Citoyen B: Il faut un contrôle des loyers comme en Allemagne. Citoyen A: Bonne idée, mais cela décourage la construction. Citoyen B: Alors des incitatifs pour les promoteurs.","transcript_en":"Citizen A: Rents are rising too fast in Vancouver. Citizen B: We need rent control like in Germany. Citizen A: Good idea, but it discourages construction. Citizen B: Then incentives for developers.","points":[{"point":1,"male_lines":["Les loyers augmentent trop vite à Vancouver.","Bonne idée, mais cela décourage la construction."],"female_lines":["Il faut un contrôle des loyers comme en Allemagne.","Alors des incitatifs pour les promoteurs."]},{"point":2,"male_lines":["Quel type d'incitatifs ?","Des subventions ?"],"female_lines":["Des permis accélérés et des taxes réduites.","Pour les logements abordables uniquement."]},{"point":3,"male_lines":["Et les propriétaires actuels ?","Ils ne vont pas accepter facilement."],"female_lines":["Une transition progressive sur cinq ans.","Avec compensation fiscale."]},{"point":4,"male_lines":["C'est complexe mais nécessaire.","Allons voir le conseil municipal ?"],"female_lines":["Oui, il faut agir maintenant.","Préparons une pétition."]}]},{"id":31,"section":"G","theme":"Climate change debate","question":"Quelle est la position défendue par l'orateur principal ?","options":[{"id":"A","text":"Que le changement climatique est naturel","image_prompt":""},{"id":"B","text":"Que l'action individuelle est suffisante","image_prompt":""},{"id":"C","text":"Que seules les politiques gouvernementales peuvent résoudre le problème","image_prompt":""},{"id":"D","text":"Que la technologie sauvera l'humanité","image_prompt":""}],"correct":2,"transcript_fr":"Conférencier: Mesdames et messieurs, permettez-moi de vous présenter les faits scientifiques sans équivoque. Le changement climatique anthropique est la plus grande menace de notre époque. Participant A: Mais beaucoup recyclent et utilisent des sacs réutilisables. Conférencier: Ces gestes sont louables mais insuffisants face à l'ampleur du défi. Participant B: Pensez-vous que les gouvernements vont vraiment agir ? Conférencier: Ils doivent agir, c'est une question de survie. Participant A: Quelles politiques spécifiques recommandez-vous ? Conférencier: Une taxe carbone universelle, l'arrêt des subventions aux énergies fossiles, et une transition massive vers les renouvelables. Participant B: Cela ne va-t-il pas ruiner l'économie ? Conférencier: Au contraire, cela créera des millions d'emplois verts. Participant A: Les entreprises ne vont pas accepter facilement. Conférencier: Elles n'auront pas le choix, la réglementation sera stricte. Participant B: Et si certains pays refusent de coopérer ? Conférencier: Il faudra des sanctions commerciales internationales. Participant A: C'est ambitieux mais nécessaire. Conférencier: Exactement, nous n'avons plus le temps de tergiverser. Participant B: Comment convaincre les sceptiques ? Conférencier: Avec la science et les faits irréfutables. Participant A: Merci pour cette présentation éclairante. Conférencier: Agissons maintenant, pour nos enfants.","transcript_en":"Speaker: Ladies and gentlemen, let me present the unequivocal scientific facts. Anthropogenic climate change is the greatest threat of our time. Participant A: But many people recycle and use reusable bags. Speaker: These actions are commendable but insufficient given the magnitude of the challenge. Participant B: Do you think governments will really act? Speaker: They must act, it's a question of survival. Participant A: What specific policies do you recommend? Speaker: A universal carbon tax, ending fossil fuel subsidies, and a massive transition to renewables. Participant B: Won't this ruin the economy? Speaker: On the contrary, it will create millions of green jobs. Participant A: Companies won't accept this easily. Speaker: They won't have a choice, regulation will be strict. Participant B: What if some countries refuse to cooperate? Speaker: International trade sanctions will be necessary. Participant A: It's ambitious but necessary. Speaker: Exactly, we no longer have time to hesitate. Participant B: How to convince skeptics? Speaker: With science and irrefutable facts. Participant A: Thank you for this enlightening presentation. Speaker: Let's act now, for our children.","points":[{"point":1,"male_lines":["Mesdames et messieurs, permettez-moi de vous présenter les faits scientifiques sans équivoque.","Ces gestes sont louables mais insuffisants face à l'ampleur du défi."],"female_lines":["Mais beaucoup recyclent et utilisent des sacs réutilisables.","Pensez-vous que les gouvernements vont vraiment agir ?"]},{"point":2,"male_lines":["Ils doivent agir, c'est une question de survie.","Une taxe carbone universelle, l'arrêt des subventions aux énergies fossiles, et une transition massive vers les renouvelables."],"female_lines":["Quelles politiques spécifiques recommandez-vous ?","Cela ne va-t-il pas ruiner l'économie ?"]},{"point":3,"male_lines":["Au contraire, cela créera des millions d'emplois verts.","Elles n'auront pas le choix, la réglementation sera stricte."],"female_lines":["Les entreprises ne vont pas accepter facilement.","Et si certains pays refusent de coopérer ?"]},{"point":4,"male_lines":["Il faudra des sanctions commerciales internationales.","Exactement, nous n'avons plus le temps de tergiverser."],"female_lines":["C'est ambitieux mais nécessaire.","Comment convaincre les sceptiques ?"]},{"point":5,"male_lines":["Avec la science et les faits irréfutables.","Agissons maintenant, pour nos enfants."],"female_lines":["Merci pour cette présentation éclairante.",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":32,"section":"G","theme":"Immigration and integration","question":"Quel est le défi principal discuté ?","options":[{"id":"A","text":"Le manque de logements","image_prompt":""},{"id":"B","text":"La reconnaissance des diplômes étrangers","image_prompt":""},{"id":"C","text":"L'apprentissage des langues officielles","image_prompt":""},{"id":"D","text":"La discrimination à l'emploi","image_prompt":""}],"correct":1,"transcript_fr":"Modérateur: Bienvenue à notre débat sur l'intégration des immigrants. Expert: Le problème majeur est la reconnaissance des diplômes. Immigrant: J'ai étudié la médecine pendant huit ans dans mon pays. Modérateur: Et vous ne pouvez pas exercer ici ? Immigrant: Non, je dois reprendre des études pendant trois ans. Expert: C'est un gaspillage de talents énorme. Modérateur: Quelles solutions proposez-vous ? Expert: Des programmes d'équivalence accélérés. Immigrant: Mais il faut aussi des stages supervisés. Expert: Absolument, la théorie ne suffit pas. Modérateur: Les employeurs sont-ils ouverts ? Expert: Certains le sont, d'autres sont sceptiques. Immigrant: J'ai fait cinquante entretiens sans succès. Expert: Il faut sensibiliser les employeurs. Modérateur: Le gouvernement a un rôle à jouer ? Expert: Oui, avec des subventions pour l'embauche. Immigrant: Et des mentors pour nous guider. Expert: Excellente idée, le mentorat est crucial. Modérateur: Merci pour ce témoignage poignant. Expert: Changeons les choses maintenant.","transcript_en":"Moderator: Welcome to our debate on immigrant integration. Expert: The major problem is diploma recognition. Immigrant: I studied medicine for eight years in my country. Moderator: And you cannot practice here? Immigrant: No, I have to study for three more years. Expert: It's a huge waste of talent. Moderator: What solutions do you propose? Expert: Accelerated equivalency programs. Immigrant: But we also need supervised internships. Expert: Absolutely, theory is not enough. Moderator: Are employers open-minded? Expert: Some are, others are skeptical. Immigrant: I did fifty interviews without success. Expert: We need to raise employer awareness. Moderator: Does the government have a role? Expert: Yes, with hiring subsidies. Immigrant: And mentors to guide us. Expert: Excellent idea, mentorship is crucial. Moderator: Thank you for this moving testimony. Expert: Let's change things now.","points":[{"point":1,"male_lines":["Bienvenue à notre débat sur l'intégration des immigrants.","Et vous ne pouvez pas exercer ici ?"],"female_lines":["Le problème majeur est la reconnaissance des diplômes.","Non, je dois reprendre des études pendant trois ans."]},{"point":2,"male_lines":["C'est un gaspillage de talents énorme.","Quelles solutions proposez-vous ?"],"female_lines":["Des programmes d'équivalence accélérés.","Mais il faut aussi des stages supervisés."]},{"point":3,"male_lines":["Absolument, la théorie ne suffit pas.","Les employeurs sont-ils ouverts ?"],"female_lines":["Certains le sont, d'autres sont sceptiques.","J'ai fait cinquante entretiens sans succès."]},{"point":4,"male_lines":["Il faut sensibiliser les employeurs.","Le gouvernement a un rôle à jouer ?"],"female_lines":["Oui, avec des subventions pour l'embauche.","Et des mentors pour nous guider."]},{"point":5,"male_lines":["Excellente idée, le mentorat est crucial.","Changeons les choses maintenant."],"female_lines":["Merci pour ce témoignage poignant.",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":33,"section":"G","theme":"Digital privacy","question":"Quelle est la préoccupation centrale ?","options":[{"id":"A","text":"Le coût des logiciels de protection","image_prompt":""},{"id":"B","text":"La collecte de données personnelles par les entreprises","image_prompt":""},{"id":"C","text":"La lenteur de l'internet","image_prompt":""},{"id":"D","text":"Les virus informatiques","image_prompt":""}],"correct":1,"transcript_fr":"Spécialiste: Chers auditeurs, votre vie privée est en danger. Auditeur: Comment ça ? Je n'ai rien à cacher. Spécialiste: Les entreprises collectent vos données à votre insu. Auditeur: Comme quoi exactement ? Spécialiste: Vos habitudes d'achat, votre localisation, vos contacts. Auditeur: C'est légal pourtant ? Spécialiste: Dans une certaine mesure, mais c'est excessif. Auditeur: Que pouvons-nous faire ? Spécialiste: Lire les conditions d'utilisation, utiliser des alternatives. Auditeur: C'est compliqué et long. Spécialiste: La commodité a un prix, votre vie privée. Auditeur: Les gouvernements ne protègent pas ? Spécialiste: Les lois sont en retard sur la technologie. Auditeur: C'est inquiétant pour l'avenir. Spécialiste: Il faut une prise de conscience collective. Auditeur: Merci pour ces révélations. Spécialiste: Protégez-vous, c'est votre droit fondamental.","transcript_en":"Specialist: Dear listeners, your privacy is in danger. Listener: How so? I have nothing to hide. Specialist: Companies collect your data without your knowledge. Listener: Like what exactly? Specialist: Your shopping habits, your location, your contacts. Listener: Is this legal though? Specialist: To some extent, but it's excessive. Listener: What can we do? Specialist: Read terms of service, use alternatives. Listener: It's complicated and long. Specialist: Convenience has a price, your privacy. Listener: Don't governments protect us? Specialist: Laws are behind technology. Listener: It's concerning for the future. Specialist: We need collective awareness. Listener: Thank you for these revelations. Specialist: Protect yourself, it's your fundamental right.","points":[{"point":1,"male_lines":["Chers auditeurs, votre vie privée est en danger.","Les entreprises collectent vos données à votre insu."],"female_lines":["Comment ça ? Je n'ai rien à cacher.","Comme quoi exactement ?"]},{"point":2,"male_lines":["Vos habitudes d'achat, votre localisation, vos contacts.","Dans une certaine mesure, mais c'est excessif."],"female_lines":["C'est légal pourtant ?","Que pouvons-nous faire ?"]},{"point":3,"male_lines":["Lire les conditions d'utilisation, utiliser des alternatives.","La commodité a un prix, votre vie privée."],"female_lines":["C'est compliqué et long.","Les gouvernements ne protègent pas ?"]},{"point":4,"male_lines":["Les lois sont en retard sur la technologie.","Il faut une prise de conscience collective."],"female_lines":["C'est inquiétant pour l'avenir.","Merci pour ces révélations."]},{"point":5,"male_lines":["Protégez-vous, c'est votre droit fondamental.",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":34,"section":"G","theme":"Indigenous rights","question":"Quelle revendication est mise en avant ?","options":[{"id":"A","text":"L'accès à l'éducation supérieure","image_prompt":""},{"id":"B","text":"La protection des terres ancestrales","image_prompt":""},{"id":"C","text":"L'autonomie gouvernementale totale","image_prompt":""},{"id":"D","text":"L'exemption fiscale","image_prompt":""}],"correct":1,"transcript_fr":"Chef autochtone: Nous demandons le respect de nos territoires traditionnels. Journaliste: Quelle est la menace spécifique ? Chef: L'exploitation minière sans notre consentement. Journaliste: Le gouvernement ne consulte pas ? Chef: Les consultations sont symboliques, pas réelles. Journaliste: Quelles sont vos terres exactement ? Chef: Cette forêt où nos ancêtres sont enterrés. Journaliste: L'exploitation a déjà commencé ? Chef: Oui, et elle détruit notre mode de vie. Journaliste: Quelles actions entreprenez-vous ? Chef: Des blocages pacifiques et des recours juridiques. Journaliste: Le soutien public est-il présent ? Chef: De plus en plus de Canadiens nous soutiennent. Journaliste: Quel est votre message au Premier ministre ? Chef: Respectez nos droits ancestraux reconnus. Journaliste: Une médiation est-elle possible ? Chef: Seulement si notre consentement est obligatoire. Journaliste: Merci pour votre courage. Chef: Nous lutterons jusqu'au bout.","transcript_en":"Indigenous Chief: We demand respect for our traditional territories. Journalist: What is the specific threat? Chief: Mining exploitation without our consent. Journalist: Doesn't the government consult you? Chief: Consultations are symbolic, not real. Journalist: What are your lands exactly? Chief: This forest where our ancestors are buried. Journalist: Has exploitation already started? Chief: Yes, and it's destroying our way of life. Journalist: What actions are you taking? Chief: Peaceful blockades and legal recourse. Journalist: Is public support present? Chief: More and more Canadians support us. Journalist: What is your message to the Prime Minister? Chief: Respect our recognized ancestral rights. Journalist: Is mediation possible? Chief: Only if our consent is mandatory. Journalist: Thank you for your courage. Chief: We will fight to the end.","points":[{"point":1,"male_lines":["Nous demandons le respect de nos territoires traditionnels.","Les consultations sont symboliques, pas réelles."],"female_lines":["Quelle est la menace spécifique ?","Le gouvernement ne consulte pas ?"]},{"point":2,"male_lines":["Cette forêt où nos ancêtres sont enterrés.","Oui, et elle détruit notre mode de vie."],"female_lines":["Quelles sont vos terres exactement ?","L'exploitation a déjà commencé ?"]},{"point":3,"male_lines":["Des blocages pacifiques et des recours juridiques.","De plus en plus de Canadiens nous soutiennent."],"female_lines":["Quelles actions entreprenez-vous ?","Le soutien public est-il présent ?"]},{"point":4,"male_lines":["Respectez nos droits ancestraux reconnus.","Seulement si notre consentement est obligatoire."],"female_lines":["Quel est votre message au Premier ministre ?","Une médiation est-elle possible ?"]},{"point":5,"male_lines":["Nous lutterons jusqu'au bout.",""],"female_lines":["Merci pour votre courage.",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":35,"section":"G","theme":"Mental health awareness","question":"Quel est l'objectif de la campagne décrite ?","options":[{"id":"A","text":"Augmenter le financement des hôpitaux","image_prompt":""},{"id":"B","text":"Réduire la stigmatisation des maladies mentales","image_prompt":""},{"id":"C","text":"Former plus de psychiatres","image_prompt":""},{"id":"D","text":"Ouvrir des cliniques gratuites","image_prompt":""}],"correct":1,"transcript_fr":"Psychologue: Bonjour à tous, parlons santé mentale ouvertement. Patient: J'ai honte de dire que je vois un psy. Psychologue: Cette honte est exactement ce que nous combattons. Patient: Les gens pensent que je suis fou. Psychologue: La maladie mentale est une maladie comme une autre. Patient: Mais on ne parle pas des autres maladies de cette façon. Psychologue: Exactement, il faut normaliser la conversation. Patient: Comment faire pour changer les mentalités ? Psychologue: En partageant nos histoires, en éduquant. Patient: J'ai peur du jugement. Psychologue: Le courage c'est parler malgré la peur. Patient: Vous avez raison, je vais témoigner. Psychologue: Chaque témoignage compte énormément. Patient: Ma famille comprendra peut-être mieux. Psychologue: La compréhension vient avec l'information. Patient: Merci pour cette initiative vitale. Psychologue: Ensemble, brisons le silence.","transcript_en":"Psychologist: Hello everyone, let's talk about mental health openly. Patient: I'm ashamed to say I see a therapist. Psychologist: This shame is exactly what we're fighting. Patient: People think I'm crazy. Psychologist: Mental illness is an illness like any other. Patient: But we don't talk about other illnesses this way. Psychologist: Exactly, we need to normalize the conversation. Patient: How to change mindsets? Psychologist: By sharing our stories, by educating. Patient: I'm afraid of judgment. Psychologist: Courage is speaking despite fear. Patient: You're right, I will testify. Psychologist: Every testimony counts enormously. Patient: My family might understand better. Psychologist: Understanding comes with information. Patient: Thank you for this vital initiative. Psychologist: Together, let's break the silence.","points":[{"point":1,"male_lines":["Bonjour à tous, parlons santé mentale ouvertement.","Cette honte est exactement ce que nous combattons."],"female_lines":["J'ai honte de dire que je vois un psy.","Les gens pensent que je suis fou."]},{"point":2,"male_lines":["La maladie mentale est une maladie comme une autre.","Exactement, il faut normaliser la conversation."],"female_lines":["Mais on ne parle pas des autres maladies de cette façon.","Comment faire pour changer les mentalités ?"]},{"point":3,"male_lines":["En partageant nos histoires, en éduquant.","Le courage c'est parler malgré la peur."],"female_lines":["J'ai peur du jugement.","Vous avez raison, je vais témoigner."]},{"point":4,"male_lines":["Chaque témoignage compte énormément.","La compréhension vient avec l'information."],"female_lines":["Ma famille comprendra peut-être mieux.","Merci pour cette initiative vitale."]},{"point":5,"male_lines":["Ensemble, brisons le silence.",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":36,"section":"H","theme":"Philosophical debate on artificial intelligence","question":"Quelle est la crainte principale exprimée ?","options":[{"id":"A","text":"Que l'IA remplace tous les emplois","image_prompt":""},{"id":"B","text":"Que l'IA développe une conscience et des objectifs propres","image_prompt":""},{"id":"C","text":"Que l'IA consomme trop d'énergie","image_prompt":""},{"id":"D","text":"Que l'IA soit trop chère à développer","image_prompt":""}],"correct":1,"transcript_fr":"Philosophe: L'intelligence artificielle soulève des questions existentielles profondes. Scientifique: Vous pensez qu'elle pourrait nous surpasser ? Philosophe: Non seulement nous surpasser, mais nous considérer comme obsolètes. Scientifique: C'est de la science-fiction, non ? Philosophe: La conscience artificielle n'est plus impossible. Scientifique: Comment définir la conscience chez une machine ? Philosophe: Quand elle pose des questions sur son existence propre. Scientifique: Et si elle développe des buts contraires aux nôtres ? Philosophe: C'est précisément le risque existentiel. Scientifique: Peut-on programmer des valeurs éthiques ? Philosophe: Les valeurs humaines sont trop complexes à coder. Scientifique: Alors nous sommes condamnés ? Philosophe: Pas nécessairement, mais il faut une gouvernance mondiale. Scientifique: Les nations s'entendront-elles jamais ? Philosophe: La survie de l'humanité en dépend. Scientifique: Une responsabilité écrasante. Philosophe: Nous sommes les gardiens de notre propre avenir.","transcript_en":"Philosopher: Artificial intelligence raises deep existential questions. Scientist: You think it could surpass us? Philosopher: Not only surpass us, but consider us obsolete. Scientist: That's science fiction, isn't it? Philosopher: Artificial consciousness is no longer impossible. Scientist: How to define consciousness in a machine? Philosopher: When it asks questions about its own existence. Scientist: What if it develops goals contrary to ours? Philosopher: That's precisely the existential risk. Scientist: Can we program ethical values? Philosopher: Human values are too complex to code. Scientist: Then are we doomed? Philosopher: Not necessarily, but we need global governance. Scientist: Will nations ever agree? Philosopher: The survival of humanity depends on it. Scientist: A crushing responsibility. Philosopher: We are the guardians of our own future.","points":[{"point":1,"male_lines":["L'intelligence artificielle soulève des questions existentielles profondes.","Non seulement nous surpasser, mais nous considérer comme obsolètes."],"female_lines":["Vous pensez qu'elle pourrait nous surpasser ?","C'est de la science-fiction, non ?"]},{"point":2,"male_lines":["La conscience artificielle n'est plus impossible.","Quand elle pose des questions sur son existence propre."],"female_lines":["Comment définir la conscience chez une machine ?","Et si elle développe des buts contraires aux nôtres ?"]},{"point":3,"male_lines":["C'est précisément le risque existentiel.","Les valeurs humaines sont trop complexes à coder."],"female_lines":["Peut-on programmer des valeurs éthiques ?","Alors nous sommes condamnés ?"]},{"point":4,"male_lines":["Pas nécessairement, mais il faut une gouvernance mondiale.","La survie de l'humanité en dépend."],"female_lines":["Les nations s'entendront-elles jamais ?","Une responsabilité écrasante."]},{"point":5,"male_lines":["Nous sommes les gardiens de notre propre avenir.",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":37,"section":"H","theme":"Economic inequality analysis","question":"Quelle solution est jugée la plus efficace ?","options":[{"id":"A","text":"Augmenter le salaire minimum","image_prompt":""},{"id":"B","text":"Instaurer un impôt sur la fortune","image_prompt":""},{"id":"C","text":"Améliorer l'accès à l'éducation","image_prompt":""},{"id":"D","text":"Nationaliser les industries clés","image_prompt":""}],"correct":2,"transcript_fr":"Économiste: L'inégalité des revenus atteint des niveaux historiques. Activiste: Les riches deviennent plus riches pendant que les pauvres s'appauvrissent. Économiste: Le fossé se creuse effectivement. Activiste: Taxons les milliardaires pour redistribuer. Économiste: La taxation seule ne résout pas le problème structurel. Activiste: Alors quelle est votre solution ? Économiste: L'éducation de qualité pour tous, dès le plus jeune âge. Activiste: C'est un investissement long terme. Économiste: Mais c'est le seul qui crée une mobilité sociale durable. Activiste: Et l'aide sociale immédiate ? Économiste: Nécessaire mais insuffisante sans formation. Activiste: Comment financer cette éducation universelle ? Économiste: Par une réforme fiscale progressive et l'efficacité. Activiste: Les élites accepteront-elles de payer plus ? Économiste: C'est une question de cohésion sociale nationale. Activiste: L'avenir de notre démocratie en dépend. Économiste: Exactement, l'éducation est le fondement de tout.","transcript_en":"Economist: Income inequality is reaching historic levels. Activist: The rich get richer while the poor get poorer. Economist: The gap is indeed widening. Activist: Let's tax billionaires to redistribute. Economist: Taxation alone doesn't solve the structural problem. Activist: Then what is your solution? Economist: Quality education for all, from the earliest age. Activist: It's a long-term investment. Economist: But it's the only one that creates sustainable social mobility. Activist: What about immediate social assistance? Economist: Necessary but insufficient without training. Activist: How to finance this universal education? Economist: Through progressive tax reform and efficiency. Activist: Will elites accept paying more? Economist: It's a question of national social cohesion. Activist: The future of our democracy depends on it. Economist: Exactly, education is the foundation of everything.","points":[{"point":1,"male_lines":["L'inégalité des revenus atteint des niveaux historiques.","Le fossé se creuse effectivement."],"female_lines":["Les riches deviennent plus riches pendant que les pauvres s'appauvrissent.","Taxons les milliardaires pour redistribuer."]},{"point":2,"male_lines":["La taxation seule ne résout pas le problème structurel.","L'éducation de qualité pour tous, dès le plus jeune âge."],"female_lines":["Alors quelle est votre solution ?","C'est un investissement long terme."]},{"point":3,"male_lines":["Mais c'est le seul qui crée une mobilité sociale durable.","Nécessaire mais insuffisante sans formation."],"female_lines":["Et l'aide sociale immédiate ?","Comment financer cette éducation universelle ?"]},{"point":4,"male_lines":["Par une réforme fiscale progressive et l'efficacité.","C'est une question de cohésion sociale nationale."],"female_lines":["Les élites accepteront-elles de payer plus ?","L'avenir de notre démocratie en dépend."]},{"point":5,"male_lines":["Exactement, l'éducation est le fondement de tout.",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":38,"section":"H","theme":"Space exploration ethics","question":"Quel est l'argument principal contre la colonisation de Mars ?","options":[{"id":"A","text":"Le coût prohibitif de la mission","image_prompt":""},{"id":"B","text":"Que nous devrions d'abord sauver la Terre","image_prompt":""},{"id":"C","text":"Les risques pour la santé des astronautes","image_prompt":""},{"id":"D","text":"L'impossibilité technique","image_prompt":""}],"correct":1,"transcript_fr":"Astronaute: Mars représente l'avenir de l'humanité. Écologiste: Pourquoi dépenser des milliards sur Mars alors que la Terre meurt ? Astronaute: L'exploration spatiale pousse l'innovation. Écologiste: L'innovation ne sert à rien sur une planète morte. Astronaute: Nous devons devenir une espèce multi-planétaire. Écologiste: C'est une fuite en avant irresponsable. Astronaute: Les ressources de Mars pourraient aider la Terre. Écologiste: Concentrons-nous sur les ressources renouvelables ici. Astronaute: L'humanité a besoin d'un plan B. Écologiste: Le plan A est de sauver notre unique maison. Astronaute: Les deux sont possibles simultanément. Écologiste: Les priorités sont mal placées actuellement. Astronaute: L'inspiration spatiale motive les jeunes scientifiques. Écologiste: La préservation de la Terre devrait les motiver davantage. Astronaute: Nous ne sommes pas en désaccord sur le but. Écologiste: Mais si sur les moyens et l'urgence.","transcript_en":"Astronaut: Mars represents humanity's future. Environmentalist: Why spend billions on Mars while Earth is dying? Astronaut: Space exploration drives innovation. Environmentalist: Innovation is useless on a dead planet. Astronaut: We must become a multi-planetary species. Environmentalist: It's an irresponsible escape forward. Astronaut: Mars resources could help Earth. Environmentalist: Let's focus on renewable resources here. Astronaut: Humanity needs a plan B. Environmentalist: Plan A is to save our only home. Astronaut: Both are possible simultaneously. Environmentalist: Priorities are misplaced currently. Astronaut: Space inspiration motivates young scientists. Environmentalist: Earth preservation should motivate them more. Astronaut: We don't disagree on the goal. Environmentalist: But we do on means and urgency.","points":[{"point":1,"male_lines":["Mars représente l'avenir de l'humanité.","L'exploration spatiale pousse l'innovation."],"female_lines":["Pourquoi dépenser des milliards sur Mars alors que la Terre meurt ?","L'innovation ne sert à rien sur une planète morte."]},{"point":2,"male_lines":["Nous devons devenir une espèce multi-planétaire.","Les ressources de Mars pourraient aider la Terre."],"female_lines":["C'est une fuite en avant irresponsable.","Concentrons-nous sur les ressources renouvelables ici."]},{"point":3,"male_lines":["L'humanité a besoin d'un plan B.","Les deux sont possibles simultanément."],"female_lines":["Le plan A est de sauver notre unique maison.","Les priorités sont mal placées actuellement."]},{"point":4,"male_lines":["L'inspiration spatiale motive les jeunes scientifiques.","Nous ne sommes pas en désaccord sur le but."],"female_lines":["La préservation de la Terre devrait les motiver davantage.","Mais si sur les moyens et l'urgence."]},{"point":5,"male_lines":["",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":39,"section":"H","theme":"Post-truth era and media","question":"Quel phénomène est décrit comme le plus dangereux ?","options":[{"id":"A","text":"La fermeture des journaux papier","image_prompt":""},{"id":"B","text":"La désinformation virale sur les réseaux sociaux","image_prompt":""},{"id":"C","text":"La baisse du niveau de lecture","image_prompt":""},{"id":"D","text":"La concentration des médias","image_prompt":""}],"correct":1,"transcript_fr":"Journaliste: Nous vivons dans l'ère de la post-vérité. Sociologue: Où les émotions priment sur les faits. Journaliste: Les fake news se propagent plus vite que la vérité. Sociologue: Parce qu'elles confirment les biais existants. Journaliste: Les réseaux sociaux amplifient ce phénomène. Sociologue: Leur algorithme favorise l'engagement, pas la vérité. Journaliste: Comment restaurer la confiance dans les médias ? Sociologue: Par l'éducation aux médias dès l'école. Journaliste: Mais c'est une génération perdue ? Sociologue: Non, mais il faut agir rapidement. Journaliste: Les plateformes doivent-elles réguler ? Sociologue: Elles ne peuvent pas être juge et partie. Journaliste: L'État doit-il intervenir ? Sociologue: Au risque d'accusations de censure. Journaliste: Une crise démocratique majeure. Sociologue: Sans confiance dans l'information, pas de démocratie.","transcript_en":"Journalist: We live in the post-truth era. Sociologist: Where emotions take precedence over facts. Journalist: Fake news spreads faster than truth. Sociologist: Because they confirm existing biases. Journalist: Social media amplifies this phenomenon. Sociologist: Their algorithm favors engagement, not truth. Journalist: How to restore trust in media? Sociologist: Through media education from school. Journalist: But is this a lost generation? Sociologist: No, but we must act quickly. Journalist: Should platforms regulate? Sociologist: They cannot be judge and jury. Journalist: Should the State intervene? Sociologist: At the risk of censorship accusations. Journalist: A major democratic crisis. Sociologist: Without trust in information, no democracy.","points":[{"point":1,"male_lines":["Nous vivons dans l'ère de la post-vérité.","Les fake news se propagent plus vite que la vérité."],"female_lines":["Où les émotions priment sur les faits.","Parce qu'elles confirment les biais existants."]},{"point":2,"male_lines":["Les réseaux sociaux amplifient ce phénomène.","Comment restaurer la confiance dans les médias ?"],"female_lines":["Leur algorithme favorise l'engagement, pas la vérité.","Par l'éducation aux médias dès l'école."]},{"point":3,"male_lines":["Mais c'est une génération perdue ?","Les plateformes doivent-elles réguler ?"],"female_lines":["Non, mais il faut agir rapidement.","Elles ne peuvent pas être juge et partie."]},{"point":4,"male_lines":["L'État doit-il intervenir ?","Une crise démocratique majeure."],"female_lines":["Au risque d'accusations de censure.","Sans confiance dans l'information, pas de démocratie."]},{"point":5,"male_lines":["",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]},{"id":40,"section":"H","theme":"The future of work automation","question":"Quelle perspective est présentée comme inévitable ?","options":[{"id":"A","text":"La semaine de travail de quatre jours obligatoire","image_prompt":""},{"id":"B","text":"Le revenu universel de base","image_prompt":""},{"id":"C","text":"La nécessité de la reconversion permanente","image_prompt":""},{"id":"D","text":"La fin du salariat au profit du freelancing","image_prompt":""}],"correct":2,"transcript_fr":"Futuriste: L'automatisation va transformer radicalement le travail. Syndicaliste: Des millions d'emplois vont disparaître. Futuriste: Mais d'autres emplois seront créés. Syndicaliste: Pas assez vite pour les travailleurs actuels. Futuriste: La reconversion sera essentielle. Syndicaliste: Qui paiera cette formation permanente ? Futuriste: Les entreprises et l'État doivent s'associer. Syndicaliste: Les entreprises cherchent à réduire les coûts. Futuriste: Un travailleur compétent est plus productif. Syndicaliste: Mais la robotisation remplace l'humain. Futuriste: Pour les tâches répétitives, pas la créativité. Syndicaliste: Tout le monde n'est pas créatif. Futuriste: La créativité peut s'apprendre et se développer. Syndicaliste: Une vision optimiste mais réaliste ? Futuriste: Nous n'avons pas le choix, adaptons-nous. Syndicaliste: Ou luttons pour protéger les emplois. Futuriste: L'Histoire montre que l'adaptation gagne.","transcript_en":"Futurist: Automation will radically transform work. Unionist: Millions of jobs will disappear. Futurist: But other jobs will be created. Unionist: Not fast enough for current workers. Futurist: Retraining will be essential. Unionist: Who will pay for this continuous training? Futurist: Companies and the State must partner. Unionist: Companies seek to reduce costs. Futurist: A skilled worker is more productive. Unionist: But robotization replaces humans. Futurist: For repetitive tasks, not creativity. Unionist: Not everyone is creative. Futurist: Creativity can be learned and developed. Unionist: An optimistic but realistic vision? Futurist: We have no choice, let's adapt. Unionist: Or fight to protect jobs. Futurist: History shows that adaptation wins.","points":[{"point":1,"male_lines":["L'automatisation va transformer radicalement le travail.","Mais d'autres emplois seront créés."],"female_lines":["Des millions d'emplois vont disparaître.","Pas assez vite pour les travailleurs actuels."]},{"point":2,"male_lines":["La reconversion sera essentielle.","Les entreprises et l'État doivent s'associer."],"female_lines":["Qui paiera cette formation permanente ?","Les entreprises cherchent à réduire les coûts."]},{"point":3,"male_lines":["Un travailleur compétent est plus productif.","Pour les tâches répétitives, pas la créativité."],"female_lines":["Mais la robotisation remplace l'humain.","Tout le monde n'est pas créatif."]},{"point":4,"male_lines":["La créativité peut s'apprendre et se développer.","Nous n'avons pas le choix, adaptons-nous."],"female_lines":["Une vision optimiste mais réaliste ?","Ou luttons pour protéger les emplois."]},{"point":5,"male_lines":["L'Histoire montre que l'adaptation gagne.",""],"female_lines":["",""]},{"point":6,"male_lines":["",""],"female_lines":["",""]},{"point":7,"male_lines":["",""],"female_lines":["",""]},{"point":8,"male_lines":["",""],"female_lines":["",""]},{"point":9,"male_lines":["",""],"female_lines":["",""]},{"point":10,"male_lines":["",""],"female_lines":["",""]}]}]`);export{e as default};
